// suggest_specialty pg_trgm scoring is executed via the rpc function
// public.suggest_specialty_score(complaint text) — see n8n/README.md for CREATE FUNCTION.
// Equivalent SQL:
//   SELECT s.id AS specialty_id, s.name_ar, s.name_en, s.code, s.color_hex,
//          GREATEST(similarity(p.pattern_ar, $1), 0) * p.weight AS score
//     FROM chief_complaint_patterns p JOIN specialties s ON s.id = p.specialty_id
//    WHERE p.pattern_ar % $1 OR similarity(p.pattern_ar, $1) > 0.15
//    ORDER BY score DESC LIMIT 5;
function isPlaceholder(s){ if(typeof s!=='string') return false; return /USER_.*_PLACEHOLDER|PLACEHOLDER|YOUR_.*|<<.*>>|\{\{.*\}\}/i.test(s) || /^[A-Z_]{8,}$/.test(s); }
var inp=$input.first().json; if(inp && inp.ok===false){ return [{json:inp}]; }
var cc=(inp.chief_complaint||'').toString();
if(!cc || isPlaceholder(cc)) return [{json:{ok:false,data:null,error_code:'PLACEHOLDER_DETECTED',message_for_agent:"Re-extract the actual value from the caller's spoken words.",meta:{version:'v1'}}}];
if(cc.trim().length<3) return [{json:{ok:false,data:null,error_code:'INPUT_TOO_SHORT',message_for_agent:'Ask the caller to describe the complaint in a few words.',meta:{version:'v1'}}}];
var normalized=cc.trim().replace(/[\u064B-\u0652\u0670]/g,'').toLowerCase();
return [{json:{conversation_id:inp.conversation_id||null,chief_complaint:cc.trim(),normalized:normalized,_t0:inp._t0}}];

var inp=$input.first().json; if(inp && inp.ok===false){ return [{json:inp}]; }
if(inp.ok===false) return [{json:inp}];
var base=$env.SUPABASE_URL, key=$env.SUPABASE_SERVICE_ROLE_KEY, helpers=this.helpers; var Hget={apikey:key,Authorization:'Bearer '+key}; var Hjson={apikey:key,Authorization:'Bearer '+key,'Content-Type':'application/json'};
var rows=[];
try{ rows=await helpers.httpRequest({method:'POST',url:base+'/rest/v1/rpc/suggest_specialty_score',headers:Hjson,body:{complaint:inp.normalized},json:true}); }
catch(e){ return [{json:{ok:false,data:null,error_code:'SCORING_FAILED',message_for_agent:'Specialty scoring is unavailable; ask the caller to pick a clinic.',meta:{version:'v1'}}}]; }
if(!Array.isArray(rows)) rows=(rows && rows.data)?rows.data:[];
var map=new Map();
for(var i=0;i<rows.length;i++){ var r=rows[i]; var cur=map.get(r.specialty_id)||{specialty_id:r.specialty_id,name_ar:r.name_ar,name_en:r.name_en,code:r.code,color_hex:r.color_hex,score:0}; cur.score+=Number(r.score)||0; map.set(r.specialty_id,cur); }
var specs=Array.from(map.values()).sort(function(a,b){return b.score-a.score;});
var total=specs.reduce(function(s,x){return s+x.score;},0);
var suggestions=specs.slice(0,2).map(function(x){return {specialty_id:x.specialty_id,name_ar:x.name_ar,name_en:x.name_en,code:x.code,color_hex:x.color_hex,confidence: total>0?Math.min(1,x.score/total):0};});
var top=suggestions[0]||null;
return [{json:{conversation_id:inp.conversation_id,chief_complaint:inp.chief_complaint,suggestions:suggestions,top_specialty_id: top?top.specialty_id:null, top_confidence: top?Math.min(1,top.confidence):0,_t0:inp._t0}}];

