var latency=inp._t0?(Date.now()-inp._t0):null;
var payload={conversation_id:inp.conversation_id||null,tool_name:'suggest_specialty',request_json:{chief_complaint:inp.chief_complaint},response_json:{top_specialty_id:inp.top_specialty_id,top_confidence:inp.top_confidence,suggestions:inp.suggestions},ok:true,error_code:null,latency_ms:latency};
try{ if(inp.conversation_id){ await helpers.httpRequest({method:'POST',url:base+'/rest/v1/tool_calls',headers:Object.assign({},Hjson,{Prefer:'return=minimal'}),body:payload,json:true}); } }catch(e){}
return [{json:inp}];

var inp=$input.first().json;
if(inp.ok===false) return [{json:{ok:false,data:null,message_for_agent:inp.message_for_agent||null,error_code:inp.error_code,meta:{version:'v1'}}}];
var empty=!inp.suggestions || inp.suggestions.length===0;
return [{json:{ok:true,data:{suggestions:inp.suggestions||[],top_specialty_id:inp.top_specialty_id||null,top_confidence:inp.top_confidence||0},message_for_agent: empty?'No specialty matched; ask the caller to pick directly.':null,error_code:null,meta:{version:'v1',duration_ms: inp._t0?(Date.now()-inp._t0):null}}}];
